//! # bowl-probe-ffn — the τ-bowl gate on REAL K-quant FFN weights.
//!
//! `bowl-probe` analyses the Q8_0 embedding; this probe extends to the **FFN
//! weight matrices** (Q6_K `ffn_down`, Q5_0 `ffn_gate`) — the layers where the
//! LLM.int8 "outlier features" live, i.e. where we expect the gate to behave
//! differently than on the well-behaved embedding. Dequant uses the
//! `kquant_dequant` primitives, each VERIFIED against the crate's tested
//! `mat_vec_dispatch_batch` kernel, behind the same abort-on-garbage sanity gate.
//!
//! Usage: bowl-probe-ffn [--knot PATH] [--layer N] [--max-rows N]
//! Default knot: ~/.edgework/models/qwen2.5-0.5b-instruct.knot

use distributed_inference::conformal_gate::ResidualCalibration;
use distributed_inference::kquant_dequant::{dequantize_q5_0_row, dequantize_q6k_row};
use distributed_inference::kv_cache_e8::{
    bowl_gate_report, characterize_kv_cell_filling, mean_sq_quant_error, quantize_kv_into,
    KvCentering, KvQuantConfig, KvQuantizer,
};
use distributed_inference::loader::KnotWeights;

fn analyze(name: &str, tiles: &[Vec<f32>], cols: usize) {
    // sanity gate
    let (mut finite, mut max_abs, mut sumsq, mut n) = (true, 0.0f32, 0.0f64, 0usize);
    for t in tiles {
        for &v in t {
            if !v.is_finite() { finite = false; }
            max_abs = max_abs.max(v.abs());
            sumsq += v as f64 * v as f64;
            n += 1;
        }
    }
    let std = (sumsq / n.max(1) as f64).sqrt();
    if !finite || !(1e-7..=100.0).contains(&max_abs) || !(1e-8..=10.0).contains(&std) {
        eprintln!("  ABORT (sanity): {name} finite={finite} max|w|={max_abs:.4} std={std:.6} — refusing to report.");
        return;
    }
    let step = (std as f32 / 4.0).max(1e-5);
    let report = characterize_kv_cell_filling(tiles, step);
    let mse_cubic = mean_sq_quant_error(tiles, KvQuantizer::Cubic, KvCentering::PerVectorMean, step);
    let mse_e8 = mean_sq_quant_error(tiles, KvQuantizer::E8Tail, KvCentering::PerVectorMean, step);
    let l2_scale = mse_cubic.sqrt() * (cols as f64).sqrt();
    let gamma = 2.0 * l2_scale;
    let rc = bowl_gate_report(tiles, KvQuantizer::Cubic, step, gamma);
    let re = bowl_gate_report(tiles, KvQuantizer::E8Tail, step, gamma);

    // conformal on E8 residuals (70/30 row split)
    let split = tiles.len() * 7 / 10;
    let resid = |lo: usize, hi: usize| -> Vec<f64> {
        let mut out = vec![0.0f32; cols];
        let mut v = Vec::new();
        for t in &tiles[lo..hi] {
            quantize_kv_into(t, &mut out, &KvQuantConfig { quantizer: KvQuantizer::E8Tail, centering: KvCentering::PerVectorMean, step });
            let mut s = 0.0f64;
            for j in 0..cols { let e = (t[j] - out[j]) as f64; s += e * e; }
            v.push(s.sqrt());
        }
        v
    };
    let cal = ResidualCalibration::from_residuals(&resid(0, split));
    let test = resid(split, tiles.len());
    let lie99 = { let q = cal.conformal_quantile(0.99); test.iter().filter(|&&x| x > q).count() as f64 / test.len() as f64 };

    println!(
        "  {name}: std={std:.5} cell-filling={} (eff_dim {:.0}/{} |corr|{:.3}) | E8 vs cubic MSE {:+.1}% | \
         energy accept cubic={:.0}% E8={:.0}% | conformal q.99 lie={:.2}%",
        if report.is_cell_filling { "YES" } else { "no" },
        report.effective_dim, report.dim, report.mean_abs_corr,
        (1.0 - mse_e8 / mse_cubic) * 100.0,
        100.0 * rc.accept_rate_l2, 100.0 * re.accept_rate_l2,
        100.0 * lie99,
    );
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let mut knot = format!("{}/.edgework/models/qwen2.5-0.5b-instruct.knot", std::env::var("HOME").unwrap_or_default());
    let mut layer = 0usize;
    let mut max_rows = 8000usize;
    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--knot" => { knot = args[i + 1].clone(); i += 2; }
            "--layer" => { layer = args[i + 1].parse().unwrap(); i += 2; }
            "--max-rows" => { max_rows = args[i + 1].parse().unwrap(); i += 2; }
            _ => i += 1,
        }
    }
    eprintln!("[bowl-probe-ffn] loading {knot}");
    let kw = KnotWeights::load(&knot).unwrap_or_else(|e| { eprintln!("FATAL load: {e}"); std::process::exit(2); });
    let cfg = kw.config.as_ref().unwrap_or_else(|| { eprintln!("FATAL: no config"); std::process::exit(2); });
    let (hidden, inter) = (cfg.hidden_dim, cfg.intermediate_size);
    eprintln!("[bowl-probe-ffn] hidden={hidden} intermediate={inter} layer={layer}");
    println!("\n[REAL FFN WEIGHTS | qwen2.5-0.5b layer {layer}]");

    // ffn_down: Q6_K, shape [hidden, intermediate] (cols=inter, must be ÷256)
    let down = format!("blk_{layer}_ffn_down_weight");
    if let Some(info) = kw.metadata.get(&down) {
        let (rows, cols) = (hidden, inter);
        let bytes = kw.backend.fetch_tensor(&down).unwrap();
        let raw: &[u8] = bytes.as_ref();
        let expect = rows * (cols / 256) * 210;
        if info.tensor_type == "Q6_K" && cols % 256 == 0 && raw.len() >= expect {
            let nr = rows.min(max_rows);
            let mut tiles = Vec::with_capacity(nr);
            let mut row = vec![0.0f32; cols];
            for r in 0..nr { dequantize_q6k_row(&mut row, raw, r, cols); tiles.push(row.clone()); }
            analyze(&format!("{down} (Q6_K {rows}x{cols})"), &tiles, cols);
        } else {
            eprintln!("  skip {down}: type={} cols%256={} len {}/{}", info.tensor_type, cols % 256, raw.len(), expect);
        }
    }

    // ffn_gate: Q5_0, shape [intermediate, hidden] (cols=hidden)
    let gate = format!("blk_{layer}_ffn_gate_weight");
    if let Some(info) = kw.metadata.get(&gate) {
        let (rows, cols) = (inter, hidden);
        let bytes = kw.backend.fetch_tensor(&gate).unwrap();
        let raw: &[u8] = bytes.as_ref();
        let expect = rows * cols.div_ceil(32) * 22;
        if info.tensor_type == "Q5_0" && raw.len() >= expect {
            let nr = rows.min(max_rows);
            let mut tiles = Vec::with_capacity(nr);
            let mut row = vec![0.0f32; cols];
            for r in 0..nr { dequantize_q5_0_row(&mut row, raw, r, cols); tiles.push(row.clone()); }
            analyze(&format!("{gate} (Q5_0 {rows}x{cols})"), &tiles, cols);
        } else {
            eprintln!("  skip {gate}: type={} len {}/{}", info.tensor_type, raw.len(), expect);
        }
    }
    println!("[bowl-probe-ffn] done — REAL K-quant FFN weights.");
}
